// imageSubtypeLabel maps a rule ID to a localized image sub-type label used
// as a sub-group heading inside the Images category card.
func imageSubtypeLabel(ctx context.Context, ruleID string) string {
	switch {
	case strings.HasPrefix(ruleID, "thumb_"):
		return t(ctx, "settings.image_subtype.thumbnail")
	case strings.HasPrefix(ruleID, "fanart_"):
		return t(ctx, "settings.image_subtype.fanart")
	case strings.HasPrefix(ruleID, "logo_"):
		return t(ctx, "settings.image_subtype.logo")
	case strings.HasPrefix(ruleID, "banner_"):
		return t(ctx, "settings.image_subtype.banner")
	case strings.HasPrefix(ruleID, "backdrop_"):
		return t(ctx, "settings.image_subtype.backdrop")
	default:
		return t(ctx, "settings.image_subtype.general")
	}
}

// rulesForImageSubtype returns rules whose ID starts with the given prefix.
func rulesForImageSubtype(rules []rule.Rule, prefix string) []rule.Rule {
	var out []rule.Rule
	for _, r := range rules {
		if strings.HasPrefix(r.ID, prefix) {
			out = append(out, r)
		}
	}
	return out
}

// rulesForImageSubtypeFallback returns rules whose ID does not start with any
// recognized image sub-type prefix. These are grouped under a "General" heading.
func rulesForImageSubtypeFallback(rules []rule.Rule) []rule.Rule {
	var out []rule.Rule
	for _, r := range rules {
		matched := false
		for _, pfx := range imageSubtypePrefixes {
			if strings.HasPrefix(r.ID, pfx) {
				matched = true
				break
			}
		}
		if !matched {
			out = append(out, r)
		}
	}
	return out
}

// ruleCatalogueURL returns the absolute URL of a rule's section in the rules
// catalogue page on the docs site. The MkDocs Material toc plugin slugifies
// each H2 heading by lowercasing and replacing whitespace with hyphens; the
// codegen rule names map to that same slug, so we reproduce the slugify rule
// here rather than wire a separate manifest. Punctuation that mkdocs strips
// (the slash in "Artist/ID mismatch" -> "artistid-mismatch") is handled
// inline.
func ruleCatalogueURL(name string) string {
	slug := strings.ToLower(name)
	// Drop characters mkdocs strips entirely.
	slug = strings.NewReplacer("/", "", "(", "", ")", "", ",", "", ".", "", ":", "").Replace(slug)
	// Collapse runs of whitespace to a single hyphen.
	slug = strings.Join(strings.Fields(slug), "-")
	return "https://sydlexius.github.io/stillwater/reference/rules-catalogue/#" + slug
}

// categoryLabel returns a human-readable label for a rule category.
func categoryLabel(category string) string {
	switch category {
	case "nfo":
		return "NFO"
	case "image":
		return "Images"
	case "metadata":
		return "Metadata"
	default:
		return category
	}
}

// scopePillClasses returns CSS classes for API token scope pills.
func scopePillClasses(scope string) string {
	scope = strings.TrimSpace(scope)
	switch scope {
	case "read":
		return "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300"
	case "write":
		return "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300"
	case "webhook":
		return "bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300"
	case "admin":
		return "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300"
	default:
		return "bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300"
	}
}

// tokenAfterRequest returns an inline JS handler for token lifecycle buttons.
// Revoke reloads the page so the token moves to the archive section correctly.
// Delete fades out the row. Errors show a toast.
func tokenAfterRequest(rowID, action string) string {
	if action == "revoke" {
		return "if(event.detail.successful) { " +
			"showSuccessToast('revoke successful'); " +
			"setTimeout(function(){ window.location.reload(); }, 500); " +
			"} else { try { var r=JSON.parse(event.detail.xhr.responseText); " +
			"showToast(r.error||'Operation failed'); } catch(e) { showToast('Operation failed'); } }"
	}
	return "if(event.detail.successful) { " +
		"var row = document.getElementById('" + rowID + "'); " +
		"if(row) { row.style.transition='opacity 0.3s'; row.style.opacity='0'; " +
		"setTimeout(function(){ row.remove(); }, 300); } " +
		"showSuccessToast('" + action + " successful'); " +
		"} else { try { var r=JSON.parse(event.detail.xhr.responseText); " +
		"showToast(r.error||'Operation failed'); } catch(e) { showToast('Operation failed'); } }"
}

func hasActiveTokens(tokens []auth.APIToken) bool {
	for _, t := range tokens {
		if t.Status == auth.TokenStatusActive {
			return true
		}
	}
	return false
}

func hasRevokedTokens(tokens []auth.APIToken) bool {
	for _, t := range tokens {
		if t.Status == auth.TokenStatusRevoked {
			return true
		}
	}
	return false
}

func countRevokedTokens(tokens []auth.APIToken) int {
	n := 0
	for _, t := range tokens {
		if t.Status == auth.TokenStatusRevoked {
			n++
		}
	}
	return n
}

// ruleToggleBtnClasses returns CSS classes for the enabled/disabled toggle button.
func ruleToggleBtnClasses(enabled bool) string {
	base := "relative inline-flex h-6 w-11 shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 dark:focus:ring-offset-gray-800"
	if enabled {
		return base + " bg-blue-600"
	}
	return base + " bg-gray-200 dark:bg-gray-600"
}

// ruleToggleKnobClasses returns CSS classes for the toggle knob span.
func ruleToggleKnobClasses(enabled bool) string {
	base := "pointer-events-none inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out"
	if enabled {
		return base + " translate-x-5"
	}
	return base + " translate-x-0"
}

// severityBadgeClasses returns Tailwind CSS classes for a severity badge.
func severityBadgeClasses(severity string) string {
	switch severity {
	case "error":
		return "bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300"
	case "warning":
		return "bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-300"
	default:
		return "bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300"
	}
}

// ruleHasConfig returns true if the rule has user-configurable parameters.
func ruleHasConfig(id string) bool {
	switch id {
	case "thumb_min_res", "thumb_square", "fanart_min_res", "fanart_aspect",
		"logo_min_res", "banner_min_res", "bio_exists", "logo_padding",
		"discography_populated":
		return true
	}
	return false
}

// intOrDefault formats an int for use in an HTML input value, using def when v is zero.
func intOrDefault(v, def int) string {
	if v == 0 {
		return fmt.Sprintf("%d", def)
	}
	return fmt.Sprintf("%d", v)
}

// floatOrDefault formats a float64 for use in an HTML input value, using def when v is zero.
func floatOrDefault(v, def float64) string {
	val := v
	if val == 0 {
		val = def
	}
	return fmt.Sprintf("%g", val)
}

// stringOrDefault returns v for an HTML input value, falling back to def when v
// is empty. Used for text-valued rule config fields (e.g. the discography
// release-type filter) so a freshly seeded rule shows its default in the form.
func stringOrDefault(v, def string) string {
	if v == "" {
		return def
	}
	return v
}

// defaultMinWidth returns the default minimum width for a given rule.
func defaultMinWidth(id string) int {
	switch id {
	case "thumb_min_res":
		return 500
	case "fanart_min_res":
		return 1920
	case "logo_min_res":
		return 400
	case "banner_min_res":
		return 1000
	}
	return 0
}

// defaultMinHeight returns the default minimum height for a given rule.
func defaultMinHeight(id string) int {
	switch id {
	case "thumb_min_res":
		return 500
	case "fanart_min_res":
		return 1080
	case "banner_min_res":
		return 185
	}
	return 0
}

// defaultAspectRatio returns the default aspect ratio for a given rule.
func defaultAspectRatio(id string) float64 {
	switch id {
	case "thumb_square":
		return 1.0
	case "fanart_aspect":
		return 16.0 / 9.0
	}
	return 1.0
}

// floatNear returns true if a and b are within 0.001 of each other.
func floatNear(a, b float64) bool {
	d := a - b
	if d < 0 {
		d = -d
	}
	return d < 0.001
}

// fanartResPresetKey returns the preset key matching the given fanart resolution,
// defaulting to 1080p when both values are zero.
func fanartResPresetKey(w, h int) string {
	if w == 0 {
		w = 1920
	}
	if h == 0 {
		h = 1080
	}
	switch {
	case w == 1280 && h == 720:
		return "720p"
	case w == 1920 && h == 1080:
		return "1080p"
	case w == 2560 && h == 1440:
		return "1440p"
	case w == 3840 && h == 2160:
		return "4k"
	}
	return "custom"
}

// thumbResPresetKey returns the preset key for a thumbnail resolution.
func thumbResPresetKey(w, h int) string {
	if w == 0 {
		w = 500
	}
	if h == 0 {
		h = 500
	}
	switch {
	case w == 500 && h == 500:
		return "std"
	case w == 1000 && h == 1000:
		return "hd"
	case w == 2000 && h == 2000:
		return "ultra"
	}
	return "custom"
}

// logoWidthPresetKey returns the preset key for a logo minimum width.
func logoWidthPresetKey(w int) string {
	if w == 0 {
		w = 400
	}
	switch w {
	case 400:
		return "std"
	case 800:
		return "large"
	}
	return "custom"
}

// bannerResPresetKey returns the preset key for a banner resolution.
func bannerResPresetKey(w, h int) string {
	if w == 0 {
		w = 1000
	}
	if h == 0 {
		h = 185
	}
	switch {
	case w == 758 && h == 140:
		return "kodi"
	case w == 1000 && h == 185:
		return "wide"
	}
	return "custom"
}

// fanartAspectPresetKey returns the preset key for a fanart aspect ratio.
func fanartAspectPresetKey(ratio float64) string {
	if ratio == 0 {
		ratio = 16.0 / 9.0
	}
	switch {
	case floatNear(ratio, 16.0/9.0):
		return "16:9"
	case floatNear(ratio, 1.6):
		return "16:10"
	case floatNear(ratio, 2.0):
		return "2:1"
	}
	return "custom"
}

// thumbAspectPresetKey returns the preset key for a thumbnail aspect ratio.
func thumbAspectPresetKey(ratio float64) string {
	if ratio == 0 {
		ratio = 1.0
	}
	if floatNear(ratio, 1.0) {
		return "1:1"
	}
	return "custom"
}

// providerIsAvailable returns true if a provider has a key configured or does not require one.
func providerIsAvailable(name provider.ProviderName, keys []provider.ProviderKeyStatus) bool {
	for _, k := range keys {
		if k.Name == name {
			return k.Status != "unconfigured"
		}
	}
	// Web search providers are not in the key list; check separately.
	if isWebSearchProvider(name) {
		return true
	}
	return false
}

// availableProviders filters a priority list to only providers that are configured
// and not structurally excluded for the given field (e.g. MusicBrainz never
// provides biography text, so it is excluded from the biography priority list).
func availableProviders(pri provider.FieldPriority, keys []provider.ProviderKeyStatus) []provider.ProviderName {
	var result []provider.ProviderName
	for _, p := range pri.Providers {
		if provider.IsExcludedForField(pri.Field, p) {
			continue
		}
		if providerIsAvailable(p, keys) {
			result = append(result, p)
		}
	}
	return result
}

// providerIsDisabled returns true if a provider is in the field's disabled list.
func providerIsDisabled(name provider.ProviderName, disabled []provider.ProviderName) bool {
	for _, d := range disabled {
		if d == name {
			return true
		}
	}
	return false
}

// connectionsForType filters connections by type.
func connectionsForType(conns []connection.Connection, connType string) []connection.Connection {
	var result []connection.Connection
	for _, c := range conns {
		if c.Type == connType {
			result = append(result, c)
		}
	}
	return result
}

// hasOKConnection returns true if any connection in the slice has status "ok".
func hasOKConnection(conns []connection.Connection) bool {
	for _, c := range conns {
		if c.Status == "ok" {
			return true
		}
	}
	return false
}

// webSearchToggleJSON generates the JSON body for a web search toggle request.
func webSearchToggleJSON(enabled bool) string {
	if enabled {
		return `{"enabled":true}`
	}
	return `{"enabled":false}`
}

// isWebSearchProvider returns true if the provider is a web search provider.
func isWebSearchProvider(name provider.ProviderName) bool {
	for _, n := range provider.AllWebSearchProviderNames() {
		if n == name {
			return true
		}
	}
	return false
}

